/*==============================================================*/
/* Table: CCTORD                                                */
/*==============================================================*/
CREATE TABLE IF NOT EXISTS CCTORD
(
    ID_CCTORD_CODE       INT NOT NULL AUTO_INCREMENT,
    XID_CATCLI_CODE      VARCHAR(16),
    XID_CATSTATUS_CODE   VARCHAR(4),
    XID_CATPRI_CODE      VARCHAR(4) NOT NULL,
    CCTORD_LOTE          VARCHAR(16),
    CCTORD_AMOUNT        INT NOT NULL,
    CCTORD_DELIVER_AT    TIMESTAMP NOT NULL,
    CCTORD_ORDER         INT,
    CCTORD_OBSERVATION   VARCHAR(256),
    CCTORD_DIFERENCE     INT,
    CCTORD_VALID_FROM    TIMESTAMP,
    CCTORD_VALID_TO      TIMESTAMP NULL,
    CCTORD_CREATED_BY    VARCHAR(16),
    CCTORD_UPDATED_BY    VARCHAR(16),
    CCTORD_CREATED_AT    TIMESTAMP,
    CCTORD_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CCTORD_CODE)
);

ALTER TABLE CCTORD COMMENT 'PEDIDOS';

CREATE TABLE CATPRI
(
    ID_CATPRI_CODE       VARCHAR(4) NOT NULL,
    CATPRI_NAME          VARCHAR(32) NOT NULL,
    CATPRI_TYPE          VARCHAR(4) NOT NULL,
    CATPRI_ICON          VARCHAR(32) NOT NULL,
    CATPRI_COLOR         VARCHAR(32),
    CATPRI_VALID_FROM    TIMESTAMP,
    CATPRI_VALID_TO      TIMESTAMP NULL,
    CATPRI_CREATED_BY    VARCHAR(16),
    CATPRI_UPDATED_BY    VARCHAR(16),
    CATPRI_CREATED_AT    TIMESTAMP,
    CATPRI_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CATPRI_CODE)
);

ALTER TABLE CATPRI COMMENT 'CATALOGO PRIORIDAD';


ALTER TABLE CCTORD ADD CONSTRAINT XID_CCTORD_CODE_XID_CATCLI_CODE FOREIGN KEY (XID_CATCLI_CODE)
    REFERENCES CATCLI (ID_CATCLI_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CCTORD ADD CONSTRAINT XID_CCTORD_CODE_XID_CATSTATUS_CODE FOREIGN KEY (XID_CATSTATUS_CODE)
    REFERENCES CATSTATUS (ID_CATSTATUS_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CCTORD ADD CONSTRAINT XID_CCTORD_CODE_XID_CATPRI_CODE FOREIGN KEY (XID_CATPRI_CODE)
    REFERENCES CATPRI (ID_CATPRI_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;






